// Validate input, then build the dead-letter record.
// Rejecting bad writes loudly beats storing garbage silently.
const REQUIRED = ['source_workflow', 'event_key', 'payload'];

const SECRET_PATTERNS = [
  new RegExp('sk' + '-[A-Za-z0-9_-]{10,}', 'g'),
  new RegExp('xox' + 'b-[A-Za-z0-9-]{10,}', 'g'),
  new RegExp('gh' + 'p_[A-Za-z0-9]{20,}', 'g'),
  new RegExp('Bearer\\s+[A-Za-z0-9._~+/-]{15,}', 'gi'),
];

function sanitize(value) {
  let out = String(value == null ? '' : value);
  for (const pattern of SECRET_PATTERNS) {
    out = out.replace(pattern, '[REDACTED]');
  }
  return out.slice(0, 2000);
}

const results = [];
for (const item of $input.all()) {
  const data = item.json || {};
  const missing = REQUIRED.filter((f) => {
    const v = data[f];
    return v === undefined || v === null || v === '';
  });
  if (missing.length > 0) {
    throw new Error(
      'Dead-letter write rejected: missing required field(s): ' +
        missing.join(', ') +
        '. Callers must send source_workflow, event_key, and payload.'
    );
  }

  let payloadJson = '';
  try {
    payloadJson =
      typeof data.payload === 'string'
        ? data.payload
        : JSON.stringify(data.payload);
  } catch (e) {
    throw new Error('Dead-letter write rejected: payload is not serializable: ' + e.message);
  }

  const receivedAt = new Date().toISOString();
  results.push({
    json: {
      dlq_id: String(data.event_key) + '-' + Date.now(),
      received_at: receivedAt,
      source_workflow: String(data.source_workflow),
      event_key: String(data.event_key),
      failed_node: sanitize(data.failed_node || 'unknown'),
      error_message: sanitize(data.error_message || ''),
      payload_json: payloadJson.slice(0, 45000),
      replay_target_url: String(data.replay_target_url || ''),
      status: 'pending',
      retry_count: 0,
      last_error: '',
      replayed_at: '',
    },
  });
}
return results;

