// Return a small, stable result to the calling workflow.
// Read from the validated record, not the pass-through input: if the
// best-effort Slack notify errored, its pass-through item would not
// carry the record fields.
return $('Validate And Build Record').all().map((item) => ({
  json: {
    stored: true,
    dlq_id: item.json.dlq_id,
    event_key: item.json.event_key,
    status: item.json.status,
  },
}));
